using UnityEngine;
using System;
using System.Security.Cryptography;
using System.Text;
using System.Collections.Generic;

public class SecureValue<T> where T : struct
{
    private byte[] encryptedData;
    private byte[] key;
    private byte[] iv;
    private int checksum;

    public SecureValue(T initialValue)
    {
        GenerateKey();
        SetValue(initialValue);
    }

    private void GenerateKey()
    {
        using (Aes aes = Aes.Create())
        {
            aes.GenerateKey();
            aes.GenerateIV();
            key = aes.Key;
            iv = aes.IV;
        }
    }

    public void SetValue(T value)
    {
        byte[] data = GetBytes(value);
        encryptedData = Encrypt(data);
        checksum = CalculateChecksum(data);
    }

    public T GetValue()
    {
        byte[] decryptedData = Decrypt(encryptedData);
        
        if (CalculateChecksum(decryptedData) != checksum)
        {
            Debug.LogError("Data integrity check failed! Possible memory manipulation detected.");
            Application.Quit();
            return default(T);
        }

        return FromBytes(decryptedData);
    }

    private byte[] Encrypt(byte[] data)
    {
        using (Aes aes = Aes.Create())
        {
            aes.Key = key;
            aes.IV = iv;
            using (ICryptoTransform encryptor = aes.CreateEncryptor())
            {
                return encryptor.TransformFinalBlock(data, 0, data.Length);
            }
        }
    }

    private byte[] Decrypt(byte[] data)
    {
        using (Aes aes = Aes.Create())
        {
            aes.Key = key;
            aes.IV = iv;
            using (ICryptoTransform decryptor = aes.CreateDecryptor())
            {
                return decryptor.TransformFinalBlock(data, 0, data.Length);
            }
        }
    }

    private int CalculateChecksum(byte[] data)
    {
        using (SHA256 sha256 = SHA256.Create())
        {
            byte[] hash = sha256.ComputeHash(data);
            return BitConverter.ToInt32(hash, 0);
        }
    }

    private byte[] GetBytes(T value)
    {
        if (typeof(T) == typeof(int))
        {
            return BitConverter.GetBytes((int)(object)value);
        }
        else if (typeof(T) == typeof(float))
        {
            return BitConverter.GetBytes((float)(object)value);
        }
        else if (typeof(T) == typeof(double))
        {
            return BitConverter.GetBytes((double)(object)value);
        }
        else if (typeof(T) == typeof(long))
        {
            return BitConverter.GetBytes((long)(object)value);
        }
        return new byte[0];
    }

    private T FromBytes(byte[] data)
    {
        if (typeof(T) == typeof(int))
        {
            return (T)(object)BitConverter.ToInt32(data, 0);
        }
        else if (typeof(T) == typeof(float))
        {
            return (T)(object)BitConverter.ToSingle(data, 0);
        }
        else if (typeof(T) == typeof(double))
        {
            return (T)(object)BitConverter.ToDouble(data, 0);
        }
        else if (typeof(T) == typeof(long))
        {
            return (T)(object)BitConverter.ToInt64(data, 0);
        }
        return default(T);
    }
}

public class PlayerStats : MonoBehaviour
{
    private static PlayerStats instance;
    
    private SecureValue<int> secureHealth;
    private SecureValue<int> secureMaxHealth;
    private SecureValue<int> secureCurrency;
    private SecureValue<float> secureDamageMultiplier;
    
    private float lastHealthCheck;
    private float lastCurrencyCheck;
    private float checkInterval = 0.5f;
    
    private int healthSnapshot;
    private int currencySnapshot;
    
    public int Health
    {
        get { return secureHealth.GetValue(); }
        set 
        { 
            int clampedValue = Mathf.Clamp(value, 0, MaxHealth);
            secureHealth.SetValue(clampedValue);
            ValidateHealth();
        }
    }
    
    public int MaxHealth
    {
        get { return secureMaxHealth.GetValue(); }
        set 
        { 
            secureMaxHealth.SetValue(Mathf.Max(1, value));
            if (Health > value) Health = value;
        }
    }
    
    public int Currency
    {
        get { return secureCurrency.GetValue(); }
        set 
        { 
            secureCurrency.SetValue(Mathf.Max(0, value));
            ValidateCurrency();
        }
    }
    
    public float DamageMultiplier
    {
        get { return secureDamageMultiplier.GetValue(); }
        set { secureDamageMultiplier.SetValue(Mathf.Max(0.1f, value)); }
    }

    private void Awake()
    {
        if (instance != null && instance != this)
        {
            Destroy(gameObject);
            return;
        }
        
        instance = this;
        DontDestroyOnLoad(gameObject);
        
        InitializeSecureValues();
    }

    private void InitializeSecureValues()
    {
        secureHealth = new SecureValue<int>(100);
        secureMaxHealth = new SecureValue<int>(100);
        secureCurrency = new SecureValue<int>(0);
        secureDamageMultiplier = new SecureValue<float>(1.0f);
        
        healthSnapshot = Health;
        currencySnapshot = Currency;
        lastHealthCheck = Time.time;
        lastCurrencyCheck = Time.time;
    }

    private void Update()
    {
        PerformIntegrityChecks();
    }

    private void PerformIntegrityChecks()
    {
        if (Time.time - lastHealthCheck > checkInterval)
        {
            ValidateHealth();
            lastHealthCheck = Time.time;
        }
        
        if (Time.time - lastCurrencyCheck > checkInterval)
        {
            ValidateCurrency();
            lastCurrencyCheck = Time.time;
        }
    }

    private void ValidateHealth()
    {
        int currentHealth = secureHealth.GetValue();
        
        if (currentHealth > MaxHealth)
        {
            Debug.LogError("Health manipulation detected!");
            Health = healthSnapshot;
            OnCheatDetected();
        }
        
        healthSnapshot = currentHealth;
    }

    private void ValidateCurrency()
    {
        int currentCurrency = secureCurrency.GetValue();
        
        if (currentCurrency < 0)
        {
            Debug.LogError("Currency manipulation detected!");
            Currency = currencySnapshot;
            OnCheatDetected();
        }
        
        currencySnapshot = currentCurrency;
    }

    private void OnCheatDetected()
    {
        Debug.LogError("Cheating detected! Game will close.");
        Application.Quit();
    }

    public void TakeDamage(int baseDamage)
    {
        if (baseDamage < 0)
        {
            Debug.LogWarning("Invalid damage value");
            return;
        }
        
        int calculatedDamage = CalculateDamage(baseDamage);
        Health -= calculatedDamage;
        
        if (Health <= 0)
        {
            OnPlayerDeath();
        }
    }

    private int CalculateDamage(int baseDamage)
    {
        float damage = baseDamage * DamageMultiplier;
        return Mathf.RoundToInt(damage);
    }

    public void Heal(int amount)
    {
        if (amount < 0)
        {
            Debug.LogWarning("Invalid heal amount");
            return;
        }
        
        Health = Mathf.Min(Health + amount, MaxHealth);
    }

    private void OnPlayerDeath()
    {
        Debug.Log("Player died!");
    }

    public bool CanAfford(int price)
    {
        return Currency >= price && price >= 0;
    }

    public bool Purchase(int price)
    {
        if (!CanAfford(price))
        {
            Debug.Log("Not enough currency!");
            return false;
        }
        
        Currency -= price;
        return true;
    }

    public void AddCurrency(int amount)
    {
        if (amount < 0)
        {
            Debug.LogWarning("Invalid currency amount");
            return;
        }
        
        Currency += amount;
    }
}

public class ShopItem
{
    public string itemName;
    public int basePrice;
    public ItemType type;
    public int value;
    
    public enum ItemType
    {
        HealthPotion,
        MaxHealthUpgrade,
        DamageUpgrade,
        Currency
    }
    
    public ShopItem(string name, int price, ItemType itemType, int itemValue)
    {
        itemName = name;
        basePrice = price;
        type = itemType;
        value = itemValue;
    }
    
    public int CalculatePrice(float priceMultiplier = 1.0f)
    {
        return Mathf.RoundToInt(basePrice * priceMultiplier);
    }
}

public class ShopSystem : MonoBehaviour
{
    private PlayerStats playerStats;
    private List<ShopItem> shopItems;
    private Dictionary<string, int> purchaseCount;
    
    private void Start()
    {
        playerStats = FindObjectOfType<PlayerStats>();
        purchaseCount = new Dictionary<string, int>();
        InitializeShop();
    }
    
    private void InitializeShop()
    {
        shopItems = new List<ShopItem>
        {
            new ShopItem("Health Potion", 50, ShopItem.ItemType.HealthPotion, 30),
            new ShopItem("Max Health Upgrade", 100, ShopItem.ItemType.MaxHealthUpgrade, 20),
            new ShopItem("Damage Upgrade", 150, ShopItem.ItemType.DamageUpgrade, 10),
            new ShopItem("Currency Pack", 200, ShopItem.ItemType.Currency, 500)
        };
    }
    
    public bool BuyItem(ShopItem item)
    {
        if (item == null)
        {
            Debug.LogError("Invalid item");
            return false;
        }
        
        float priceMultiplier = CalculatePriceMultiplier(item);
        int finalPrice = item.CalculatePrice(priceMultiplier);
        
        if (!playerStats.CanAfford(finalPrice))
        {
            Debug.Log($"Cannot afford {item.itemName}. Price: {finalPrice}, Currency: {playerStats.Currency}");
            return false;
        }
        
        if (!playerStats.Purchase(finalPrice))
        {
            return false;
        }
        
        ApplyItemEffect(item);
        IncrementPurchaseCount(item.itemName);
        
        Debug.Log($"Purchased {item.itemName} for {finalPrice} currency");
        return true;
    }
    
    private float CalculatePriceMultiplier(ShopItem item)
    {
        if (!purchaseCount.ContainsKey(item.itemName))
        {
            return 1.0f;
        }
        
        int count = purchaseCount[item.itemName];
        return 1.0f + (count * 0.1f);
    }
    
    private void ApplyItemEffect(ShopItem item)
    {
        switch (item.type)
        {
            case ShopItem.ItemType.HealthPotion:
                playerStats.Heal(item.value);
                Debug.Log($"Healed for {item.value} HP");
                break;
                
            case ShopItem.ItemType.MaxHealthUpgrade:
                playerStats.MaxHealth += item.value;
                playerStats.Health = playerStats.MaxHealth;
                Debug.Log($"Max health increased by {item.value}");
                break;
                
            case ShopItem.ItemType.DamageUpgrade:
                float damageIncrease = item.value / 100f;
                playerStats.DamageMultiplier += damageIncrease;
                Debug.Log($"Damage multiplier increased by {damageIncrease}");
                break;
                
            case ShopItem.ItemType.Currency:
                playerStats.AddCurrency(item.value);
                Debug.Log($"Added {item.value} currency");
                break;
        }
    }
    
    private void IncrementPurchaseCount(string itemName)
    {
        if (!purchaseCount.ContainsKey(itemName))
        {
            purchaseCount[itemName] = 0;
        }
        purchaseCount[itemName]++;
    }
    
    public int GetItemPrice(ShopItem item)
    {
        float priceMultiplier = CalculatePriceMultiplier(item);
        return item.CalculatePrice(priceMultiplier);
    }
    
    public List<ShopItem> GetShopItems()
    {
        return new List<ShopItem>(shopItems);
    }
}

